from flask import Flask, request
from prometheus_client import Counter, generate_latest, CONTENT_TYPE_LATEST

app = Flask(__name__)

# Dictionary to store counters for each user-path combination
metrics = {}

def get_metric_name(user_id, path):
    """Generate a unique metric name based on user_id and path."""
    return f'http_requests_user_{user_id}_path_{path.replace("/", "_")}'

@app.route('/metrics')
def metrics_endpoint():
    return generate_latest(), 200, {'Content-Type': CONTENT_TYPE_LATEST}

@app.before_request
def track_http_requests():
    user_id = request.args.get('user_id', 'unknown')
    session_id = request.args.get('session_id', 'unknown')
    path = request.path
    metric_name = get_metric_name(user_id, path)

    if metric_name not in metrics:
        metrics[metric_name] = Counter(metric_name, 'HTTP requests', ['user_id', 'session_id', 'path'])

    metrics[metric_name].labels(user_id=user_id, session_id=session_id, path=path).inc()

@app.route('/<path:path>', methods=['GET', 'POST', 'PUT', 'DELETE', 'PATCH'])
def catch_all(path):
    return "Request tracked", 200

if __name__ == '__main__':
    app.run(host='0.0.0.0', port=8000)